import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { certificatesAPI } from '../../services/api';
import Card from '../../components/common/Card';
import Modal from '../../components/common/Modal';
import toast from 'react-hot-toast';
import { Award, Upload, Trash2, FileText, X, Loader2, Download, ExternalLink, Eye, ZoomIn, File, Image } from 'lucide-react';

const StudentCertificates = () => {
  const { user } = useAuth();
  const [certificates, setCertificates] = useState([]);
  const [loading, setLoading] = useState(true);
  const [uploadModalOpen, setUploadModalOpen] = useState(false);
  const [previewModalOpen, setPreviewModalOpen] = useState(false);
  const [selectedCertificate, setSelectedCertificate] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [formData, setFormData] = useState({ certificateName: '', file: null });
  const [studentId, setStudentId] = useState(null);

  useEffect(() => {
    fetchCertificates();
  }, []);

  const fetchCertificates = async () => {
    try {
      const response = await certificatesAPI.getByUserId(user.id);
      if (response.data.success) {
        setCertificates(response.data.certificates);
        // Get student ID from certificates if available, or fetch it
        if (response.data.certificates.length > 0) {
          setStudentId(response.data.certificates[0].student_id);
        }
      }
    } catch (error) {
      console.error('Error fetching certificates:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleFileChange = (e) => {
    setFormData(prev => ({ ...prev, file: e.target.files[0] }));
  };

  const handleUpload = async (e) => {
    e.preventDefault();
    if (!formData.certificateName || !formData.file) {
      toast.error('Please fill all fields');
      return;
    }

    setUploading(true);
    const data = new FormData();
    data.append('userId', user.id);
    data.append('certificateName', formData.certificateName);
    data.append('certificate', formData.file);

    try {
      const response = await certificatesAPI.upload(data);
      if (response.data.success) {
        toast.success('Certificate uploaded successfully');
        setUploadModalOpen(false);
        setFormData({ certificateName: '', file: null });
        fetchCertificates();
      }
    } catch (error) {
      toast.error('Failed to upload certificate');
    } finally {
      setUploading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this certificate?')) return;

    try {
      await certificatesAPI.delete(id);
      toast.success('Certificate deleted');
      fetchCertificates();
    } catch (error) {
      toast.error('Failed to delete certificate');
    }
  };

  const openPreview = (cert) => {
    setSelectedCertificate(cert);
    setPreviewModalOpen(true);
  };

  const isImageFile = (url) => {
    const imageExtensions = ['.jpg', '.jpeg', '.png', '.gif', '.bmp', '.webp'];
    return imageExtensions.some(ext => url.toLowerCase().endsWith(ext));
  };

  const getFileExtension = (url) => {
    const parts = url.split('.');
    return parts.length > 1 ? parts.pop().toUpperCase() : 'FILE';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="w-10 h-10 animate-spin text-green-600" />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Header */}
      <div className="bg-gradient-to-r from-green-600 via-green-700 to-green-800 rounded-2xl p-6 text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2"></div>
        <div className="relative z-10 flex items-center justify-between">
          <div>
            <div className="flex items-center gap-2 text-green-200 mb-1">
              <Award className="w-4 h-4" />
              <span className="text-sm font-medium">Achievement Records</span>
            </div>
            <h1 className="text-2xl font-bold">My Certificates</h1>
            <p className="text-green-100 text-sm mt-1">{certificates.length} certificates uploaded</p>
          </div>
          <button
            onClick={() => setUploadModalOpen(true)}
            className="bg-white/20 hover:bg-white/30 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors backdrop-blur-sm"
          >
            <Upload className="w-4 h-4" />
            Upload Certificate
          </button>
        </div>
      </div>

      {/* Certificates Grid */}
      {certificates.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
          {certificates.map((cert) => (
            <div key={cert.id} className="card-hover group">
              <Card className="h-full">
                <div className="flex items-start justify-between mb-4">
                  <div className="w-14 h-14 bg-gradient-to-br from-green-400 to-green-600 rounded-xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                    <Award className="w-7 h-7 text-white" />
                  </div>
                  <button
                    onClick={() => handleDelete(cert.id)}
                    className="p-2 text-secondary-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                    title="Delete"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
                <h3 className="font-semibold text-secondary-800 mb-2 line-clamp-2">{cert.certificate_name}</h3>
                <p className="text-sm text-secondary-500 mb-4">
                  Uploaded: {new Date(cert.uploaded_at).toLocaleDateString()}
                </p>
                <a
                  href={cert.file_url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-2 text-green-600 hover:text-green-700 text-sm font-medium group/link"
                >
                  View Certificate
                  <ExternalLink className="w-4 h-4 group-hover/link:translate-x-0.5 transition-transform" />
                </a>
              </Card>
            </div>
          ))}
        </div>
      ) : (
        <Card>
          <div className="empty-state py-16">
            <div className="w-20 h-20 bg-secondary-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <FileText className="w-10 h-10 text-secondary-400" />
            </div>
            <h3 className="text-lg font-semibold text-secondary-700 mb-2">No Certificates Yet</h3>
            <p className="text-secondary-500 mb-6 max-w-sm mx-auto">
              Upload your certificates to keep track of your achievements and accomplishments
            </p>
            <button
              onClick={() => setUploadModalOpen(true)}
              className="btn-primary"
            >
              <Upload className="w-4 h-4 mr-2" />
              Upload First Certificate
            </button>
          </div>
        </Card>
      )}

      {/* Upload Modal */}
      <Modal
        isOpen={uploadModalOpen}
        onClose={() => setUploadModalOpen(false)}
        title="Upload Certificate"
      >
        <form onSubmit={handleUpload} className="space-y-5">
          <div>
            <label className="label">Certificate Name</label>
            <input
              type="text"
              value={formData.certificateName}
              onChange={(e) => setFormData(prev => ({ ...prev, certificateName: e.target.value }))}
              className="input-field"
              placeholder="e.g., Programming Competition Certificate"
              required
            />
          </div>
          <div>
            <label className="label">Certificate File</label>
            <div className="border-2 border-dashed border-secondary-200 rounded-xl p-6 text-center hover:border-primary-400 transition-colors">
              <input
                type="file"
                onChange={handleFileChange}
                className="hidden"
                id="file-upload"
                accept=".pdf,.jpg,.jpeg,.png,.doc,.docx"
                required
              />
              <label htmlFor="file-upload" className="cursor-pointer">
                <Upload className="w-8 h-8 text-secondary-400 mx-auto mb-2" />
                <p className="text-sm text-secondary-600">
                  {formData.file ? formData.file.name : 'Click to upload or drag and drop'}
                </p>
                <p className="text-xs text-secondary-400 mt-1">
                  PDF, JPG, PNG, DOC, DOCX (max 5MB)
                </p>
              </label>
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <button
              type="button"
              onClick={() => setUploadModalOpen(false)}
              className="btn-secondary flex-1"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={uploading}
              className="btn-primary flex-1 flex items-center justify-center gap-2"
            >
              {uploading && <Loader2 className="w-4 h-4 animate-spin" />}
              {uploading ? 'Uploading...' : 'Upload'}
            </button>
          </div>
        </form>
      </Modal>
    </div>
  );
};

export default StudentCertificates;
